## Sub-Agents (子体)

### 2.1 sessions_spawn 详解

**功能**: 创建隔离的子 Agent 会话，执行后台任务。

**参数**:
```typescript
{
  task: string;                    // 任务描述 (必需)
  label?: string;                  // 日志/UI 显示标签
  agentId?: string;                // 指定 Agent ID (需权限)
  model?: string;                  // 覆盖模型
  thinking?: string;               // 覆盖思考级别
  runTimeoutSeconds?: number;      // 运行超时 (0 = 无限制)
  thread?: boolean;                // 是否绑定线程 (Discord 等)
  mode?: "run" | "session";        // run=一次性, session=持久
  cleanup?: "delete" | "keep";     // 完成后是否清理 (默认 keep)
}
```

**返回值**:
```typescript
{
  status: "accepted";
  runId: string;
  childSessionKey: string;  // 如: agent:main:subagent:uuid
}
```

**Session Key 格式**:
- 一级子体: `agent:<agentId>:subagent:<uuid>`
- 二级子体: `agent:<agentId>:subagent:<uuid>:subagent:<uuid>`

### 2.2 嵌套深度控制

```json5
{
  agents: {
    defaults: {
      subagents: {
        maxSpawnDepth: 2,           // 最大嵌套深度 (1-5, 默认 1)
        maxChildrenPerAgent: 5,     // 每个 Agent 最大活跃子体数
        maxConcurrent: 8,           // 全局并发限制
        runTimeoutSeconds: 900,     // 默认超时
        archiveAfterMinutes: 60     // 自动归档时间
      }
    }
  }
}
```

**深度级别**:

| 深度 | Session Key | 角色 | 能否创建子体 |
|------|-------------|------|-------------|
| 0 | `agent:<id>:main` | 主 Agent | 是 |
| 1 | `agent:<id>:subagent:<uuid>` | 子体 (协调器) | 仅当 `maxSpawnDepth >= 2` |
| 2 | `agent:<id>:subagent:<uuid>:subagent:<uuid>` | 子-子体 (工作器) | 否 |

### 2.3 工具权限控制

**默认子体工具集**:
- 所有工具 **除了** Session 工具
- 当 `maxSpawnDepth >= 2` 时，深度 1 子体可获得:
  - `sessions_spawn`
  - `subagents`
  - `sessions_list`
  - `sessions_history`

**配置覆盖**:
```json5
{
  tools: {
    subagents: {
      tools: {
        deny: ["gateway", "cron", "write", "edit"],
        // allow: ["read", "exec", "process"]  // 如设置则变为白名单模式
      }
    }
  }
}
```

### 2.4 子体监控机制设计

**监控架构**:
```mermaid
flowchart TB
    subgraph Main["主 Agent"]
        Monitor[监控循环]
        List[sessions_list]
        History[sessions_history]
    end

    subgraph Sub1["子体 1"]
        Task1[任务执行]
    end

    subgraph Sub2["子体 2"]
        Task2[任务执行]
    end

    Monitor -->|轮询| List
    List -->|返回子体列表| Monitor
    Monitor -->|查询详情| History
    History -->|返回状态| Monitor

    Monitor -.->|超时/失败检测| Task1
    Monitor -.->|超时/失败检测| Task2

    style Main fill:#e8f5e9
    style Sub1 fill:#fff3e0
    style Sub2 fill:#fff3e0
```

**监控伪代码**:
```typescript
// 子体监控管理器
class SubAgentMonitor {
  private activeSubAgents: Map<string, SubAgentInfo> = new Map();

  // 创建子体并监控
  async spawnAndMonitor(task: string, options: SpawnOptions): Promise<string> {
    const result = await sessions_spawn({
      task,
      label: options.label,
      runTimeoutSeconds: options.timeout || 300,
      cleanup: options.cleanup || "keep"
    });

    // 记录监控信息
    this.activeSubAgents.set(result.childSessionKey, {
      sessionKey: result.childSessionKey,
      runId: result.runId,
      startTime: Date.now(),
      timeout: options.timeout || 300,
      retryCount: 0,
      maxRetries: options.maxRetries || 3
    });

    // 启动监控
    this.startMonitoring(result.childSessionKey);

    return result.childSessionKey;
  }

  // 监控循环
  async startMonitoring(sessionKey: string) {
    const info = this.activeSubAgents.get(sessionKey);
    if (!info) return;

    const checkInterval = setInterval(async () => {
      try {
        // 获取子体状态
        const sessions = await sessions_list({
          kinds: ["other"],
          activeMinutes: 1
        });

        const subAgent = sessions.find(s => s.key === sessionKey);

        if (!subAgent) {
          // 子体已结束，获取最终结果
          await this.handleCompletion(sessionKey);
          clearInterval(checkInterval);
          return;
        }

        // 检查超时
        const elapsed = (Date.now() - info.startTime) / 1000;
        if (elapsed > info.timeout) {
          await this.handleTimeout(sessionKey);
          clearInterval(checkInterval);
        }

      } catch (error) {
        console.error(`监控 ${sessionKey} 失败:`, error);
      }
    }, 5000); // 每 5 秒检查一次
  }

  // 处理完成
  async handleCompletion(sessionKey: string) {
    const info = this.activeSubAgents.get(sessionKey);

    // 获取历史记录
    const history = await sessions_history({
      sessionKey,
      limit: 50,
      includeTools: true
    });

    // 提取结果
    const result = this.extractResult(history);

    // 通知主任务
    await this.notifyParent(sessionKey, {
      status: "completed",
      result,
      runtime: Date.now() - info.startTime
    });

    this.activeSubAgents.delete(sessionKey);
  }

  // 处理超时
  async handleTimeout(sessionKey: string) {
    const info = this.activeSubAgents.get(sessionKey);

    if (info.retryCount < info.maxRetries) {
      // 重试策略
      info.retryCount++;
      console.log(`子体 ${sessionKey} 超时，第 ${info.retryCount} 次重试...`);

      // 获取原任务
      const history = await sessions_history({ sessionKey, limit: 10 });
      const originalTask = this.extractTask(history);

      // 创建新子体
      const newSessionKey = await this.spawnAndMonitor(originalTask, {
        label: `retry-${info.retryCount}`,
        timeout: info.timeout * 1.5, // 增加超时时间
        maxRetries: info.maxRetries - info.retryCount
      });

      // 更新映射
      this.activeSubAgents.delete(sessionKey);

    } else {
      // 超过重试次数，标记失败
      await this.notifyParent(sessionKey, {
        status: "failed",
        error: `超时且超过最大重试次数 (${info.maxRetries})`
      });
      this.activeSubAgents.delete(sessionKey);
    }
  }

  // 提取结果
  extractResult(history: Message[]): any {
    // 从最后一条 assistant 消息提取结果
    for (let i = history.length - 1; i >= 0; i--) {
      if (history[i].role === "assistant") {
        return history[i].content;
      }
    }
    return null;
  }
}
```

### 2.5 自动接管/重试策略

**策略 1: 超时重试**
```typescript
async function spawnWithRetry(task: string, maxRetries = 3): Promise<string> {
  let lastError;

  for (let i = 0; i < maxRetries; i++) {
    try {
      const result = await sessions_spawn({
        task,
        runTimeoutSeconds: 300 * (i + 1), // 递增超时
        label: `attempt-${i + 1}`
      });

      // 等待完成
      const completed = await waitForCompletion(result.childSessionKey, 300);
      if (completed) {
        return result.childSessionKey;
      }

    } catch (error) {
      lastError = error;
      console.log(`尝试 ${i + 1} 失败:`, error);
      await sleep(1000 * Math.pow(2, i)); // 指数退避
    }
  }

  throw new Error(`所有 ${maxRetries} 次尝试均失败: ${lastError}`);
}
```

**策略 2: 主 Agent 接管**
```typescript
async function spawnWithFallback(task: string): Promise<string> {
  try {
    // 尝试子体执行
    const subAgentKey = await spawnWithRetry(task, 2);
    return subAgentKey;

  } catch (error) {
    console.log("子体执行失败，主 Agent 接管...");

    // 主 Agent 直接执行
    const result = await exec({
      command: `echo "${task}" | openclaw agent --local --message -`
    });

    return "main-agent-fallback";
  }
}
```

**策略 3: 任务分解与并行执行**
```typescript
async function parallelSpawn(tasks: string[]): Promise<string[]> {
  // 创建多个子体
  const spawnPromises = tasks.map((task, index) => 
    sessions_spawn({
      task,
      label: `parallel-${index}`,
      runTimeoutSeconds: 600
    })
  );

  const results = await Promise.all(spawnPromises);

  // 监控所有子体
  const sessionKeys = results.map(r => r.childSessionKey);
  await monitorAll(sessionKeys);

  return sessionKeys;
}
```

