## 伪代码流程

### 6.1 主 Agent 协调多个子体

```typescript
// 主任务协调器
async function orchestrateTask(mainTask: string) {
  // 1. 分解任务
  const subTasks = await decomposeTask(mainTask);

  // 2. 并行创建子体
  const subAgents = await Promise.all(
    subTasks.map((task, index) => 
      sessions_spawn({
        task: task.description,
        label: `subtask-${index}`,
        runTimeoutSeconds: 600,
        cleanup: "keep"
      })
    )
  );

  // 3. 监控所有子体
  const sessionKeys = subAgents.map(r => r.childSessionKey);
  const results = await monitorSubAgents(sessionKeys);

  // 4. 整合结果
  const finalResult = await synthesizeResults(results);

  return finalResult;
}

// 监控子体
async function monitorSubAgents(sessionKeys: string[]): Promise<SubAgentResult[]> {
  const results: SubAgentResult[] = [];
  const pending = new Set(sessionKeys);

  while (pending.size > 0) {
    // 获取所有活跃 Session
    const sessions = await sessions_list({
      kinds: ["other"],
      activeMinutes: 5
    });

    for (const key of pending) {
      const session = sessions.find(s => s.key === key);

      if (!session) {
        // 子体已完成，获取结果
        const history = await sessions_history({ sessionKey: key, limit: 50 });
        const result = extractResult(history);
        results.push({ sessionKey: key, status: "completed", result });
        pending.delete(key);
      } else {
        // 检查是否超时
        const elapsed = Date.now() - session.updatedAt;
        if (elapsed > 600000) { // 10 分钟
          results.push({ sessionKey: key, status: "timeout" });
          pending.delete(key);
        }
      }
    }

    if (pending.size > 0) {
      await sleep(5000); // 等待 5 秒再检查
    }
  }

  return results;
}
```

### 6.2 嵌套子体 (Orchestrator 模式)

```typescript
// 配置: maxSpawnDepth = 2

// 主 Agent 创建协调器
async function createOrchestrator() {
  const orchestrator = await sessions_spawn({
    task: `你是一个任务协调器。你的职责是：
           1. 接收复杂任务
           2. 将任务分解为子任务
           3. 使用 sessions_spawn 创建工作子体
           4. 收集所有子体结果
           5. 整合并返回最终结果`,
    label: "orchestrator",
    runTimeoutSeconds: 1800
  });

  return orchestrator.childSessionKey;
}

// 向协调器发送任务
async function sendToOrchestrator(orchestratorKey: string, task: string) {
  const result = await sessions_send({
    sessionKey: orchestratorKey,
    message: task,
    timeoutSeconds: 1800
  });

  return result;
}

// 协调器内部逻辑 (在子体中执行)
async function orchestratorLogic(task: string) {
  // 分解任务
  const subTasks = analyzeAndSplit(task);

  // 创建工作子体 (深度 2)
  const workers = await Promise.all(
    subTasks.map(t => 
      sessions_spawn({
        task: t,
        label: "worker",
        runTimeoutSeconds: 600
      })
    )
  );

  // 等待所有工作子体完成 (通过 announce 接收结果)
  const results = await collectWorkerResults(workers.map(w => w.childSessionKey));

  // 整合并返回
  return synthesize(results);
}
```

### 6.3 Webhook 处理流程

```typescript
// Webhook 处理器
async function handleWebhook(request: WebhookRequest) {
  // 1. 认证检查
  if (!verifyToken(request.headers.authorization)) {
    return { status: 401, error: "Unauthorized" };
  }

  // 2. 解析请求
  const { message, agentId, channel, to, deliver } = request.body;

  // 3. 路由到指定 Agent
  const targetAgent = agentId || "main";

  // 4. 创建或获取 Session
  const sessionKey = `hook:${request.body.name || "generic"}`;

  // 5. 触发 Agent 执行
  const result = await triggerAgent({
    agentId: targetAgent,
    sessionKey,
    message,
    deliver: deliver !== false,
    channel: channel || "last",
    to
  });

  return { status: 202, runId: result.runId };
}

// Feishu 事件处理
async function handleFeishuEvent(event: FeishuEvent) {
  // 1. 解析事件
  const { message, sender, chat } = parseFeishuEvent(event);

  // 2. 根据绑定配置路由
  const binding = findBinding({
    channel: "feishu",
    peer: { kind: chat.type, id: chat.id },
    sender: sender.id
  });

  // 3. 触发对应 Agent
  const result = await triggerAgent({
    agentId: binding.agentId,
    message: message.content,
    channel: "feishu",
    to: chat.id
  });

  return result;
}
```

### 6.4 失败恢复流程

```typescript
// 带恢复机制的任务执行
async function executeWithRecovery(task: string, options: ExecutionOptions) {
  const maxRetries = options.maxRetries || 3;
  const attempts: AttemptRecord[] = [];

  for (let i = 0; i < maxRetries; i++) {
    try {
      // 尝试子体执行
      const subAgent = await sessions_spawn({
        task: `${task}\n[尝试 ${i + 1}/${maxRetries}]`,
        label: `attempt-${i + 1}`,
        runTimeoutSeconds: options.timeout || 300
      });

      // 等待完成
      const completed = await waitForSubAgent(subAgent.childSessionKey, options.timeout);

      if (completed.success) {
        return {
          success: true,
          result: completed.result,
          attempts: i + 1,
          sessionKey: subAgent.childSessionKey
        };
      }

      attempts.push({
        attempt: i + 1,
        error: completed.error,
        sessionKey: subAgent.childSessionKey
      });

    } catch (error) {
      attempts.push({
        attempt: i + 1,
        error: error.message
      });

      // 指数退避
      if (i < maxRetries - 1) {
        await sleep(1000 * Math.pow(2, i));
      }
    }
  }

  // 所有尝试失败，主 Agent 接管
  console.log("所有子体尝试失败，主 Agent 接管...");

  const fallbackResult = await executeAsMainAgent(task);

  return {
    success: fallbackResult.success,
    result: fallbackResult.result,
    attempts: maxRetries,
    fallback: true,
    previousAttempts: attempts
  };
}
```

