### 7.2 子体监控脚本

```typescript
// ~/.openclaw/workspace/scripts/subagent-monitor.ts

interface SubAgentMonitor {
  sessionKey: string;
  runId: string;
  startTime: number;
  timeout: number;
  retryCount: number;
  maxRetries: number;
  status: "running" | "completed" | "failed" | "timeout";
}

class SubAgentMonitorManager {
  private monitors: Map<string, SubAgentMonitor> = new Map();
  private checkInterval: number = 5000; // 5 秒

  async spawn(task: string, options: {
    label?: string;
    timeout?: number;
    maxRetries?: number;
  } = {}): Promise<string> {
    const result = await sessions_spawn({
      task,
      label: options.label || `monitored-${Date.now()}`,
      runTimeoutSeconds: options.timeout || 300,
      cleanup: "keep"
    });

    const monitor: SubAgentMonitor = {
      sessionKey: result.childSessionKey,
      runId: result.runId,
      startTime: Date.now(),
      timeout: (options.timeout || 300) * 1000,
      retryCount: 0,
      maxRetries: options.maxRetries || 3,
      status: "running"
    };

    this.monitors.set(result.childSessionKey, monitor);
    this.startMonitoring(result.childSessionKey);

    return result.childSessionKey;
  }

  private async startMonitoring(sessionKey: string) {
    const monitor = () => {
      this.checkStatus(sessionKey).catch(console.error);
    };

    const intervalId = setInterval(monitor, this.checkInterval);

    // 存储 intervalId 以便清理
    (this.monitors.get(sessionKey) as any).intervalId = intervalId;
  }

  private async checkStatus(sessionKey: string) {
    const monitor = this.monitors.get(sessionKey);
    if (!monitor || monitor.status !== "running") return;

    try {
      // 检查 Session 是否存在
      const sessions = await sessions_list({
        kinds: ["other"],
        activeMinutes: 1
      });

      const session = sessions.find(s => s.key === sessionKey);
      const elapsed = Date.now() - monitor.startTime;

      if (!session) {
        // Session 已结束
        await this.handleCompletion(sessionKey);
      } else if (elapsed > monitor.timeout) {
        // 超时
        await this.handleTimeout(sessionKey);
      }

    } catch (error) {
      console.error(`监控 ${sessionKey} 出错:`, error);
    }
  }

  private async handleCompletion(sessionKey: string) {
    const monitor = this.monitors.get(sessionKey);
    if (!monitor) return;

    monitor.status = "completed";

    // 获取结果
    const history = await sessions_history({
      sessionKey,
      limit: 50,
      includeTools: false
    });

    // 清理
    this.cleanup(sessionKey);

    // 通知 (可以写入文件或发送到主 Session)
    console.log(`子体 ${sessionKey} 完成`);
  }

  private async handleTimeout(sessionKey: string) {
    const monitor = this.monitors.get(sessionKey);
    if (!monitor) return;

    if (monitor.retryCount < monitor.maxRetries) {
      // 重试
      monitor.retryCount++;
      console.log(`子体 ${sessionKey} 超时，第 ${monitor.retryCount} 次重试`);

      // 获取原任务并重新创建
      // ... 重试逻辑

    } else {
      monitor.status = "timeout";
      this.cleanup(sessionKey);
      console.log(`子体 ${sessionKey} 超时且超过最大重试次数`);
    }
  }

  private cleanup(sessionKey: string) {
    const monitor = this.monitors.get(sessionKey);
    if (monitor && (monitor as any).intervalId) {
      clearInterval((monitor as any).intervalId);
    }
    this.monitors.delete(sessionKey);
  }

  getStatus(sessionKey: string): SubAgentMonitor | undefined {
    return this.monitors.get(sessionKey);
  }

  getAllStatuses(): SubAgentMonitor[] {
    return Array.from(this.monitors.values());
  }
}

// 导出单例
export const subAgentMonitor = new SubAgentMonitorManager();
```

